def topological_sort(graph, in_degree):
    queue = [n for n in graph if in_degree[n] == 0]
    result = []
    while queue:
        curr = queue.pop(0)
        result.append(curr)
        for neighbor in graph[curr]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0: queue.append(neighbor)
    return result

def schedule_intervals(intervals):
    intervals.sort(key=lambda x: x[0])
    count = 0
    last_end = float('-inf')
    for start, end in intervals:
        if start >= last_end:
            count += 1
            last_end = end
    return count

def update_segment_tree(tree, node, start, end, idx, val):
    if start == end:
        tree[node] = val
        return
    mid = (start + end) // 2
    if start <= idx <= mid: update_segment_tree(tree, 2*node, start, mid, idx, val)
    else: update_segment_tree(tree, 2*node+1, mid+1, end, idx, val)

